import { calculateGraphSize } from './calculate-graph-size.js';
import type { Orientation } from '../../../../../core/types/orientation.js';
import { ORIENTATION } from '../../../constants.js';
import type { Dimensions } from '../../../types/dimensions.js';
import type { AreasSizes } from '../types/chart-layout-internal.js';
import {
  MIN_LEGEND_HEIGHT,
  MIN_LEGEND_WIDTH,
  MIN_PLOT_SIZE,
} from '../types/constants.js';

type GetAreasSizeHandlerProps = (
  containerHeight: number,
  containerWidth: number,
  minWidth: number,
  maxWidth: number,
  resizerWrapperSize: number,
  draggedAmount: number,
  legendContainer: HTMLDivElement,
) => AreasSizes | undefined;

const getAreasWidthSize: GetAreasSizeHandlerProps = (
  containerHeight,
  containerWidth,
  minWidth,
  maxWidth,
  resizerWrapperSize,
  draggedAmount,
  legendContainer,
) => {
  const minLegendWidth = Math.min(containerWidth * minWidth, MIN_LEGEND_WIDTH);

  if (legendContainer.clientWidth - draggedAmount <= minLegendWidth) {
    const legend: Dimensions = {
      height: containerHeight,
      width: minLegendWidth,
    };

    const graph: Dimensions = {
      width: calculateGraphSize(
        containerWidth,
        minLegendWidth,
        resizerWrapperSize,
      ),
      height: containerHeight,
    };

    return { legend, graph };
  }

  const availableWidth = containerWidth - resizerWrapperSize;
  const maxWidthAllowed = Math.max(
    availableWidth * maxWidth,
    availableWidth - MIN_PLOT_SIZE,
  );

  if (legendContainer.clientWidth - draggedAmount >= maxWidthAllowed) {
    const legend: Dimensions = {
      height: containerHeight,
      width: maxWidthAllowed,
    };

    const graph: Dimensions = {
      width: calculateGraphSize(
        containerWidth,
        maxWidthAllowed,
        resizerWrapperSize,
      ),
      height: containerHeight,
    };

    return { legend, graph };
  }
};

const getAreasHeightSize: GetAreasSizeHandlerProps = (
  containerHeight,
  containerWidth,
  minHeight,
  maxHeight,
  resizerWrapperSize,
  draggedAmount,
  legendContainer,
) => {
  const minLegendHeight = Math.min(
    containerHeight * minHeight,
    MIN_LEGEND_HEIGHT,
  );

  if (legendContainer.clientHeight - draggedAmount <= minLegendHeight) {
    const legend: Dimensions = {
      height: minLegendHeight,
      width: containerWidth,
    };

    const graph: Dimensions = {
      height: calculateGraphSize(
        containerHeight,
        minLegendHeight,
        resizerWrapperSize,
      ),
      width: containerWidth,
    };

    return { legend, graph };
  }

  const availableHeight = containerHeight - resizerWrapperSize;
  const maxHeightAllowed = Math.max(
    availableHeight * maxHeight,
    availableHeight - MIN_PLOT_SIZE,
  );

  if (legendContainer.clientHeight - draggedAmount >= maxHeightAllowed) {
    const legend: Dimensions = {
      height: maxHeightAllowed,
      width: containerWidth,
    };

    const graph: Dimensions = {
      height: calculateGraphSize(
        containerHeight,
        maxHeightAllowed,
        resizerWrapperSize,
      ),
      width: containerWidth,
    };

    return { legend, graph };
  }
};

export const getDefaultAreasSize = (
  areasSizes: AreasSizes,
  draggedAmount: number,
  containerSize: number,
  resizerWrapperSize: number,
  orientation: Orientation,
) => {
  const { graph, legend } = areasSizes;

  const isVertical = orientation === ORIENTATION.Vertical;

  const legendHeight = isVertical
    ? legend.height - draggedAmount
    : legend.height;
  const legendWidth = isVertical ? legend.width : legend.width - draggedAmount;

  const graphHeight = isVertical
    ? calculateGraphSize(containerSize, legendHeight, resizerWrapperSize)
    : graph.height;
  const graphWidth = isVertical
    ? graph.width
    : calculateGraphSize(containerSize, legendWidth, resizerWrapperSize);

  return {
    legend: { height: legendHeight, width: legendWidth },
    graph: { height: graphHeight, width: graphWidth },
  };
};

export const getAreasSizeOnDragHandlers = (
  containerHeight: number,
  containerWidth: number,
  legendContainer: HTMLDivElement,
  resizerWrapperSize: number,
) => ({
  getAreasHeightSizeOnDrag: (
    minHeight: number,
    maxHeight: number,
    verticalDraggedAmount = 0,
  ) =>
    getAreasHeightSize(
      containerHeight,
      containerWidth,
      minHeight,
      maxHeight,
      resizerWrapperSize,
      verticalDraggedAmount,
      legendContainer,
    ),
  getAreasWidthSizeOnDrag: (
    minWidth: number,
    maxWidth: number,
    horizontalDraggedAmount = 0,
  ) =>
    getAreasWidthSize(
      containerHeight,
      containerWidth,
      minWidth,
      maxWidth,
      resizerWrapperSize,
      horizontalDraggedAmount,
      legendContainer,
    ),
});
